// Collect all items — students from Airtable or webhook payload
const allItems = $input.all();

// Detect source: webhook vs batch
const webhookBody = allItems[0]?.json?.body || allItems[0]?.json || {};
const isWebhook = !!webhookBody.studentId || !!webhookBody.email;

// Build student list
let students = [];
if (isWebhook) {
  // Single student from webhook
  students = [{
    studentId: webhookBody.studentId || `STU-${Date.now()}`,
    firstName: webhookBody.firstName || '',
    lastName: webhookBody.lastName || '',
    email: webhookBody.email || '',
    gpa: parseFloat(webhookBody.gpa) || 0,
    major: webhookBody.major || '',
    yearOfStudy: parseInt(webhookBody.yearOfStudy) || 1,
    nationality: webhookBody.nationality || '',
    residencyStatus: (webhookBody.residencyStatus || 'domestic').toUpperCase(),
    financialNeed: webhookBody.financialNeed === true || webhookBody.financialNeed === 'true',
    extracurriculars: Array.isArray(webhookBody.extracurriculars) ? webhookBody.extracurriculars : (webhookBody.extracurriculars || '').split(',').map(s => s.trim()).filter(Boolean),
    achievements: Array.isArray(webhookBody.achievements) ? webhookBody.achievements : (webhookBody.achievements || '').split(',').map(s => s.trim()).filter(Boolean),
    intendedCareer: webhookBody.intendedCareer || '',
    disabilityStatus: webhookBody.disabilities === true || webhookBody.disabilities === 'true',
    firstGenStudent: webhookBody.firstGenStudent === true || webhookBody.firstGenStudent === 'true',
    indigenousStatus: webhookBody.indigenousStatus === true || webhookBody.indigenousStatus === 'true',
    gender: webhookBody.gender || '',
    regionalBackground: webhookBody.regionalBackground === true || webhookBody.regionalBackground === 'true',
    notes: webhookBody.notes || ''
  }];
} else {
  // Batch from Airtable
  students = allItems
    .filter(i => i.json.fields?.['Student ID'])
    .map(i => {
      const f = i.json.fields;
      return {
        studentId: f['Student ID'],
        firstName: f['First Name'] || '',
        lastName: f['Last Name'] || '',
        email: f['Email'] || '',
        gpa: parseFloat(f['GPA']) || 0,
        major: f['Major'] || '',
        yearOfStudy: parseInt(f['Year of Study']) || 1,
        nationality: f['Nationality'] || '',
        residencyStatus: (f['Residency Status'] || 'DOMESTIC').toUpperCase(),
        financialNeed: f['Financial Need'] === true || f['Financial Need'] === 'Yes',
        extracurriculars: (f['Extracurriculars'] || '').split(',').map(s => s.trim()).filter(Boolean),
        achievements: (f['Achievements'] || '').split(',').map(s => s.trim()).filter(Boolean),
        intendedCareer: f['Intended Career'] || '',
        disabilityStatus: f['Disability Status'] === true || f['Disability Status'] === 'Yes',
        firstGenStudent: f['First Gen Student'] === true || f['First Gen Student'] === 'Yes',
        indigenousStatus: f['Indigenous Status'] === true || f['Indigenous Status'] === 'Yes',
        gender: f['Gender'] || '',
        regionalBackground: f['Regional Background'] === true || f['Regional Background'] === 'Yes',
        notes: f['Notes'] || ''
      };
    });
}

// Build scholarship list from Airtable results
const scholarships = allItems
  .filter(i => i.json.fields?.['Scholarship ID'])
  .map(i => {
    const f = i.json.fields;
    const deadline = f['Application Deadline'] ? new Date(f['Application Deadline']) : null;
    const daysToDeadline = deadline ? Math.ceil((deadline - new Date()) / (1000 * 60 * 60 * 24)) : 999;
    return {
      scholarshipId: f['Scholarship ID'],
      name: f['Name'] || '',
      provider: f['Provider'] || '',
      valueAUD: parseFloat(f['Value AUD']) || 0,
      deadline: f['Application Deadline'] || '',
      daysToDeadline,
      isUrgent: daysToDeadline <= 14,
      eligibleMajors: (f['Eligible Majors'] || 'ANY').split(',').map(s => s.trim()),
      minGPA: parseFloat(f['Min GPA']) || 0,
      yearLevels: (f['Year Levels'] || 'ANY').split(',').map(s => s.trim()),
      nationalityRequirements: f['Nationality Requirements'] || 'ANY',
      residencyRequirements: (f['Residency Requirements'] || 'ANY').toUpperCase(),
      financialNeedRequired: f['Financial Need Required'] === true || f['Financial Need Required'] === 'Yes',
      genderRequirement: f['Gender Requirement'] || 'ANY',
      disabilityPreference: f['Disability Preference'] === true || f['Disability Preference'] === 'Yes',
      firstGenPreference: f['First Gen Preference'] === true || f['First Gen Preference'] === 'Yes',
      indigenousPreference: f['Indigenous Preference'] === true || f['Indigenous Preference'] === 'Yes',
      extracurricularRequirements: f['Extracurricular Requirements'] || '',
      careerFocus: f['Career Focus'] || '',
      description: f['Description'] || '',
      applicationURL: f['Application URL'] || '',
      renewable: f['Renewable'] === true || f['Renewable'] === 'Yes',
      numberOfAwards: parseInt(f['Number of Awards']) || 1
    };
  });

// Demo scholarships if none loaded from Airtable
const demoScholarships = scholarships.length > 0 ? scholarships : [
  { scholarshipId: 'SCH-001', name: 'STEM Excellence Award', provider: 'Tech Foundation', valueAUD: 10000, deadline: '2025-07-31', daysToDeadline: 30, isUrgent: false, eligibleMajors: ['Computer Science', 'Engineering', 'Mathematics', 'Physics'], minGPA: 3.5, yearLevels: ['1', '2', '3'], nationalityRequirements: 'ANY', residencyRequirements: 'ANY', financialNeedRequired: false, genderRequirement: 'ANY', disabilityPreference: false, firstGenPreference: false, indigenousPreference: false, extracurricularRequirements: '', careerFocus: 'Technology, AI, Data Science', description: 'For outstanding STEM students demonstrating academic excellence and innovation.', applicationURL: 'https://techfoundation.org/apply', renewable: true, numberOfAwards: 5 },
  { scholarshipId: 'SCH-002', name: 'First Generation Leaders Scholarship', provider: 'National Education Trust', valueAUD: 7500, deadline: '2025-06-20', daysToDeadline: 10, isUrgent: true, eligibleMajors: ['ANY'], minGPA: 3.0, yearLevels: ['1', '2'], nationalityRequirements: 'ANY', residencyRequirements: 'DOMESTIC', financialNeedRequired: true, genderRequirement: 'ANY', disabilityPreference: false, firstGenPreference: true, indigenousPreference: false, extracurricularRequirements: 'Community service preferred', careerFocus: 'ANY', description: 'Supporting first-generation university students with demonstrated financial need.', applicationURL: 'https://netedu.org/first-gen', renewable: false, numberOfAwards: 20 },
  { scholarshipId: 'SCH-003', name: 'International Women in Tech Grant', provider: 'Global Tech Alliance', valueAUD: 15000, deadline: '2025-08-15', daysToDeadline: 55, isUrgent: false, eligibleMajors: ['Computer Science', 'Information Technology', 'Data Science'], minGPA: 3.2, yearLevels: ['2', '3', '4'], nationalityRequirements: 'ANY', residencyRequirements: 'INTERNATIONAL', financialNeedRequired: false, genderRequirement: 'Female', disabilityPreference: false, firstGenPreference: false, indigenousPreference: false, extracurricularRequirements: 'Leadership role preferred', careerFocus: 'Technology, Engineering', description: 'Empowering international women pursuing technology careers.', applicationURL: 'https://globaltechalliance.org/women', renewable: true, numberOfAwards: 3 },
  { scholarshipId: 'SCH-004', name: 'Regional Access Bursary', provider: 'State Government', valueAUD: 5000, deadline: '2025-07-01', daysToDeadline: 25, isUrgent: false, eligibleMajors: ['ANY'], minGPA: 2.5, yearLevels: ['1', '2', '3', '4'], nationalityRequirements: 'Australian', residencyRequirements: 'DOMESTIC', financialNeedRequired: true, genderRequirement: 'ANY', disabilityPreference: false, firstGenPreference: false, indigenousPreference: false, extracurricularRequirements: '', careerFocus: 'ANY', description: 'Supporting students from regional and rural backgrounds relocating for university.', applicationURL: 'https://stategov.edu.au/regional', renewable: false, numberOfAwards: 50 },
  { scholarshipId: 'SCH-005', name: 'Future AI Researchers Fellowship', provider: 'AI Research Institute', valueAUD: 25000, deadline: '2025-09-30', daysToDeadline: 90, isUrgent: false, eligibleMajors: ['Computer Science', 'Mathematics', 'Cognitive Science'], minGPA: 3.7, yearLevels: ['3', '4', 'Postgraduate'], nationalityRequirements: 'ANY', residencyRequirements: 'ANY', financialNeedRequired: false, genderRequirement: 'ANY', disabilityPreference: false, firstGenPreference: false, indigenousPreference: false, extracurricularRequirements: 'Research experience or publications preferred', careerFocus: 'Artificial Intelligence, Machine Learning', description: 'Prestigious fellowship for students committed to advancing AI research.', applicationURL: 'https://airesearch.org/fellowship', renewable: true, numberOfAwards: 2 }
];

const finalScholarships = demoScholarships;

// Demo student if none loaded
const demoStudents = students.length > 0 ? students : [{
  studentId: 'STU-DEMO-001', firstName: 'Priya', lastName: 'Sharma',
  email: 'user@example.com', gpa: 3.8,
  major: 'Computer Science', yearOfStudy: 2,
  nationality: 'Indian', residencyStatus: 'INTERNATIONAL',
  financialNeed: true, extracurriculars: ['Robotics Club', 'Volunteer Tutor'],
  achievements: ["Dean's List 2024", 'Hackathon Winner'],
  intendedCareer: 'AI Research', disabilityStatus: false,
  firstGenStudent: true, indigenousStatus: false,
  gender: 'Female', regionalBackground: false, notes: ''
}];

const finalStudents = demoStudents;

// Emit one item per student (scholarships passed as context)
return finalStudents.map(student => ({
  json: {
    student,
    scholarships: finalScholarships,
    totalScholarships: finalScholarships.length,
    runId: `MATCH-${Date.now()}-${Math.random().toString(36).substr(2,5).toUpperCase()}`
  }
}));

// Hard-filter out scholarships the student is definitively ineligible for
// before sending to Claude — reduces token cost and improves accuracy
const { student, scholarships, runId } = $input.item.json;

const candidateScholarships = scholarships.filter(sch => {
  // GPA hard cutoff
  if (student.gpa < sch.minGPA) return false;

  // Year of study check
  if (!sch.yearLevels.includes('ANY')) {
    const yearStr = String(student.yearOfStudy);
    const yearMatch = sch.yearLevels.some(y =>
      y.trim() === yearStr ||
      (y.toLowerCase().includes('post') && student.yearOfStudy > 4) ||
      y.trim() === 'ANY'
    );
    if (!yearMatch) return false;
  }

  // Residency hard check
  if (sch.residencyRequirements !== 'ANY') {
    if (sch.residencyRequirements === 'DOMESTIC' && student.residencyStatus === 'INTERNATIONAL') return false;
    if (sch.residencyRequirements === 'INTERNATIONAL' && student.residencyStatus === 'DOMESTIC') return false;
  }

  // Gender hard check
  if (sch.genderRequirement && sch.genderRequirement !== 'ANY') {
    if (student.gender && student.gender.toLowerCase() !== sch.genderRequirement.toLowerCase()) return false;
  }

  // Financial need hard check
  if (sch.financialNeedRequired && !student.financialNeed) return false;

  return true;
});

return {
  json: {
    student,
    candidateScholarships,
    eliminatedCount: scholarships.length - candidateScholarships.length,
    runId
  }
};

