const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';

if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || '';
}

const clean = aiText.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
let result;
try {
  result = JSON.parse(clean);
} catch (e) {
  const match = clean.match(/\{[\s\S]*\}/);
  if (match) {
    try { result = JSON.parse(match[0]); }
    catch (e2) {
      result = { studentId: 'PARSE_ERROR', scholarshipMatches: [], overallProfile: 'Processing error — manual review needed', topStrengths: [], profileGaps: [], topRecommendations: [], generalApplicationAdvice: '' };
    }
  }
}

const upstream = $('Pre-Filter Hard Ineligibility').item.json;

// Sort matches by score descending
const sortedMatches = (result.scholarshipMatches || []).sort((a, b) => b.matchScore - a.matchScore);

// Compute stats
const eligible = sortedMatches.filter(m => m.eligibilityStatus === 'ELIGIBLE' || m.eligibilityStatus === 'LIKELY_ELIGIBLE');
const recommended = sortedMatches.filter(m => m.recommendApply);
const urgent = recommended.filter(m => m.isUrgent);
const totalValue = recommended.reduce((sum, m) => sum + (m.valueAUD || 0), 0);

return {
  json: {
    student: upstream.student,
    runId: upstream.runId,
    aiResult: { ...result, scholarshipMatches: sortedMatches },
    stats: {
      totalEvaluated: sortedMatches.length,
      eligibleCount: eligible.length,
      recommendedCount: recommended.length,
      urgentDeadlineCount: urgent.length,
      maxPotentialValueAUD: totalValue
    },
    recommendedMatches: recommended,
    urgentMatches: urgent,
    scoredAt: new Date().toISOString()
  }
};

const d = $input.item.json;
const student = d.student;
const ai = d.aiResult;
const matches = d.recommendedMatches.slice(0, 6); // top 6
const stats = d.stats;

const urgentBanner = d.urgentMatches.length > 0
  ? `<div style="background:#fff3cd;border:2px solid #ffc107;border-radius:8px;padding:14px 18px;margin:0 0 18px;">⚡ <strong>${d.urgentMatches.length} scholarship(s) closing within 14 days!</strong> Apply immediately.</div>`
  : '';

const scholarshipCards = matches.map(m => {
  const badgeColor = m.matchScore >= 80 ? '#28a745' : m.matchScore >= 65 ? '#ffa500' : '#6c757d';
  const urgentTag = m.isUrgent ? '<span style="background:#e94560;color:white;padding:2px 7px;border-radius:3px;font-size:0.75em;margin-left:8px;">⚡ URGENT</span>' : '';
  return `
<div style="border:1px solid #e0e0e0;border-left:5px solid ${badgeColor};border-radius:6px;padding:16px 20px;margin:12px 0;">
  <div style="display:flex;justify-content:space-between;align-items:flex-start;">
    <div>
      <strong style="font-size:1.05em;color:#1a1a2e;">${m.scholarshipName}</strong>${urgentTag}
      <p style="margin:3px 0;color:#555;font-size:0.9em;">by ${m.provider}</p>
    </div>
    <div style="text-align:right;">
      <span style="background:${badgeColor};color:white;padding:4px 10px;border-radius:4px;font-weight:bold;">${m.matchScore}% Match</span>
      <p style="margin:4px 0;font-size:0.9em;color:#28a745;font-weight:bold;">A$${m.valueAUD?.toLocaleString()}</p>
    </div>
  </div>
  <p style="margin:8px 0 4px;color:#333;"><strong>Your edge:</strong> ${m.sellingPoint}</p>
  <p style="margin:4px 0;color:#555;font-size:0.9em;"><strong>Tip:</strong> ${m.applicationTip}</p>
  <p style="margin:6px 0 2px;color:#888;font-size:0.85em;">📅 Deadline: ${m.deadline} &nbsp;|&nbsp; Status: <strong>${m.eligibilityStatus.replace(/_/g,' ')}</strong></p>
  <a href="${m.applicationURL}" style="display:inline-block;margin-top:10px;background:#1a1a2e;color:white;padding:7px 16px;border-radius:4px;text-decoration:none;font-size:0.9em;">Apply Now →</a>
</div>`;
}).join('');

const htmlBody = `
<html><body style="font-family:Arial,sans-serif;max-width:680px;margin:0 auto;padding:24px;color:#222;background:#f9f9f9;">
<div style="background:linear-gradient(135deg,#1a1a2e 0%,#16213e 100%);padding:28px;border-radius:10px 10px 0 0;">
  <h1 style="color:white;margin:0;font-size:1.5em;">🎓 Your Scholarship Matches Are Ready</h1>
  <p style="color:#aaa;margin:8px 0 0;">Personalised for ${student.firstName} ${student.lastName}</p>
</div>
<div style="background:white;padding:24px;border:1px solid #ddd;">
  <p style="font-size:1.05em;">Hi <strong>${student.firstName}</strong>,</p>
  <p>Great news! Our AI scholarship matcher has found <strong>${stats.recommendedCount} scholarship opportunity${stats.recommendedCount !== 1 ? 'ies' : 'y'}</strong> matching your profile, with a combined potential value of <strong style="color:#28a745;">A$${stats.maxPotentialValueAUD.toLocaleString()}</strong>.</p>

  ${urgentBanner}

  <div style="background:#f0f4ff;border-radius:8px;padding:14px 18px;margin:14px 0;">
    <p style="margin:0;color:#1a1a2e;"><strong>Your Profile Strengths:</strong></p>
    <ul style="margin:8px 0 0;color:#333;">${(ai.topStrengths || []).map(s => `<li>${s}</li>`).join('')}</ul>
  </div>

  <h2 style="color:#1a1a2e;border-bottom:2px solid #e94560;padding-bottom:6px;">Your Top Matches</h2>
  ${scholarshipCards}

  ${ai.generalApplicationAdvice ? `<div style="background:#f8f9fa;border-radius:8px;padding:14px 18px;margin:18px 0;"><p style="margin:0;"><strong>💡 Advisor Tip:</strong> ${ai.generalApplicationAdvice}</p></div>` : ''}

  <p style="font-size:0.85em;color:#999;margin-top:24px;">This is an automated match based on your profile. Results are indicative — always read the full scholarship criteria before applying. Eligibility is not guaranteed.</p>
</div>
<div style="background:#1a1a2e;padding:14px 24px;border-radius:0 0 10px 10px;text-align:center;">
  <p style="color:#aaa;font-size:0.8em;margin:0;">AI Scholarship Matcher &bull; Unsubscribe | View in Browser</p>
</div>
</body></html>`;

return {
  json: {
    ...d,
    email: {
      to: student.email,
      subject: `🎓 ${stats.recommendedCount} Scholarship Match${stats.recommendedCount !== 1 ? 'es' : ''} Found — Up to A$${stats.maxPotentialValueAUD.toLocaleString()} Available`,
      htmlBody
    }
  }
};

